import{_ as e,o as r,c as o,a0 as a}from"./chunks/framework.B3sz4m_N.js";const s=""+new URL("../report/agentic-techniques-03-current-state.png",import.meta.url).href,m=JSON.parse(`{"title":"Current State Assessment","description":"Assessment of the Dark Factory multi-agent workflow against the Agentic Engineering Book's four pillars and maturity models.","frontmatter":{"title":"Current State Assessment","description":"Assessment of the Dark Factory multi-agent workflow against the Agentic Engineering Book's four pillars and maturity models."},"headers":[],"relativePath":"reports/agentic-engineering-techniques/03-current-state.md","filePath":"reports/agentic-engineering-techniques/03-current-state.md"}`),n={name:"reports/agentic-engineering-techniques/03-current-state.md"};function i(l,t,d,h,c,u){return r(),o("div",null,[...t[0]||(t[0]=[a('<figure class="report-section-image-wrapper" aria-labelledby="fig-current-state-caption"><img src="'+s+'" alt="An architect&#39;s blueprint table with some sections filled in and others blank" loading="lazy" class="report-section-image"><figcaption id="fig-current-state-caption">Mapping the current workflow against the four-pillar framework</figcaption></figure><h2 id="_3-current-state-assessment" tabindex="-1">3. Current State Assessment <a class="header-anchor" href="#_3-current-state-assessment" aria-label="Permalink to &quot;3. Current State Assessment&quot;">​</a></h2><h3 id="the-four-pillars" tabindex="-1">The four pillars <a class="header-anchor" href="#the-four-pillars" aria-label="Permalink to &quot;The four pillars&quot;">​</a></h3><p>The book frames agentic engineering around four interdependent pillars. Here is how the Dark Factory workflow performs against each.</p><h4 id="prompt-—-strong-foundations-missing-depth" tabindex="-1">Prompt — strong foundations, missing depth <a class="header-anchor" href="#prompt-—-strong-foundations-missing-depth" aria-label="Permalink to &quot;Prompt — strong foundations, missing depth&quot;">​</a></h4><p>The workflow&#39;s skills follow a consistent, well-structured pattern that aligns with three of the book&#39;s four core prompt principles:</p><table tabindex="0"><thead><tr><th>Principle</th><th>Status</th><th>Evidence</th></tr></thead><tbody><tr><td>Clarity over cleverness</td><td><strong>Strong</strong></td><td>Explicit role definitions, unambiguous scope</td></tr><tr><td>Structure reduces variance</td><td><strong>Strong</strong></td><td>Consistent Role → Focus → Do Not → Output Structure</td></tr><tr><td>Constraints enable creativity</td><td><strong>Strong</strong></td><td>&quot;You Focus ONLY On&quot; and &quot;You DO NOT&quot; in every skill</td></tr><tr><td>Examples beat explanations</td><td><strong>Not present</strong></td><td>No skill includes input/output examples</td></tr></tbody></table><p>The missing fourth principle — few-shot examples — is the single most impactful prompt-level gap. The book argues that examples establish format, tone, and edge-case handling more reliably than instructions alone.</p><h4 id="model-—-single-model-no-explicit-contract" tabindex="-1">Model — single model, no explicit contract <a class="header-anchor" href="#model-—-single-model-no-explicit-contract" aria-label="Permalink to &quot;Model — single model, no explicit contract&quot;">​</a></h4><p>The workflow runs on whichever model Cursor provides. There is no explicit prompt-model contract stating what the model is expected to know (WordPress APIs, ACF patterns, GDPR requirements) or how it should handle unknown domains. The only guard is the line &quot;Avoid speculative tools&quot; in the architect skill.</p><p>The book argues that every prompt makes implicit assumptions about the model. Making these explicit improves debugging — when output quality degrades, you can check whether the contract was violated rather than guessing at the cause.</p><h4 id="context-—-the-largest-gap" tabindex="-1">Context — the largest gap <a class="header-anchor" href="#context-—-the-largest-gap" aria-label="Permalink to &quot;Context — the largest gap&quot;">​</a></h4><p>Context management is the area where the workflow diverges most from the book&#39;s recommendations.</p><table tabindex="0"><thead><tr><th>Principle</th><th>Status</th><th>Impact</th></tr></thead><tbody><tr><td>One agent, one task</td><td><strong>Strong</strong></td><td>Each skill has a single focused responsibility</td></tr><tr><td>Context as working memory</td><td>Not considered</td><td>No awareness of context window constraints</td></tr><tr><td>Multi-agent context isolation</td><td><strong>Not present</strong></td><td>All agent outputs accumulate in one window</td></tr><tr><td>Orchestrator context hygiene</td><td><strong>Not present</strong></td><td>Reconciliation agent works with the most polluted context</td></tr><tr><td>Progressive disclosure</td><td><strong>Not present</strong></td><td>No mechanism to load reference material on demand</td></tr></tbody></table><p>The book&#39;s central finding on context: &quot;Token usage explains 80% of performance variance in multi-agent systems.&quot; The reconciliation agent, which does the most complex synthesis work, runs in the worst context conditions.</p><h4 id="tool-use-—-skills-pattern-is-solid-missing-layers" tabindex="-1">Tool Use — skills pattern is solid, missing layers <a class="header-anchor" href="#tool-use-—-skills-pattern-is-solid-missing-layers" aria-label="Permalink to &quot;Tool Use — skills pattern is solid, missing layers&quot;">​</a></h4><p>The workflow&#39;s use of Cursor skills (SKILL.md files with description frontmatter) directly implements the book&#39;s &quot;Skills as Meta-Tools&quot; pattern. Skills are temporary behavioural modifications that change how the agent reasons — exactly what the book describes.</p><p>However, the book&#39;s three-layer progressive disclosure model is only partially implemented:</p><table tabindex="0"><thead><tr><th>Layer</th><th>Description</th><th>Status</th></tr></thead><tbody><tr><td>Discovery</td><td>Short metadata about available capabilities</td><td>Present (description field)</td></tr><tr><td>Activation</td><td>Full instructions loaded on-demand</td><td>Present (SKILL.md body)</td></tr><tr><td>Resource</td><td>Detailed references and examples</td><td><strong>Not present</strong></td></tr></tbody></table><p>Adding a resource layer (approved tooling lists, GDPR checklists, example outputs) would give skills access to domain material without front-loading it into every prompt.</p><h3 id="prompt-maturity-assessment" tabindex="-1">Prompt maturity assessment <a class="header-anchor" href="#prompt-maturity-assessment" aria-label="Permalink to &quot;Prompt maturity assessment&quot;">​</a></h3><p>The book defines a 7-level Prompt Maturity Model. Here is where the workflow&#39;s components sit:</p><table tabindex="0"><thead><tr><th>Component</th><th>Current level</th><th>Description</th></tr></thead><tbody><tr><td>Individual skills</td><td><strong>Level 4: Contextual</strong></td><td>Read project context, produce structured output</td></tr><tr><td>One-shot runner</td><td><strong>Level 5: Higher-Order</strong> (partial)</td><td>Invokes other skills as subroutines, but not self-contained</td></tr><tr><td>Orchestration workflow</td><td><strong>Level 4: Contextual</strong></td><td>References external context but doesn&#39;t compose dynamically</td></tr><tr><td>Evaluation rubric</td><td><strong>Level 1: Static</strong></td><td>Same rubric every time, no parameterisation</td></tr></tbody></table><p>The book recommends a pyramid distribution: many Level 1–2 commands, some Level 3–4, few Level 5, rare Level 6–7. The research workflow justifies targeting Level 5 for orchestration while keeping individual skills at Level 4.</p><h3 id="orchestration-pattern-match" tabindex="-1">Orchestration pattern match <a class="header-anchor" href="#orchestration-pattern-match" aria-label="Permalink to &quot;Orchestration pattern match&quot;">​</a></h3><p>The workflow most closely resembles the book&#39;s <strong>Council Pattern</strong> — multiple read-only domain experts providing independent analysis, with a synthesis agent aggregating findings. This is a strong pattern match.</p><p>However, the Council Pattern is designed for <strong>parallel</strong> execution (all experts analyse simultaneously, synthesis happens after). The current workflow runs sequentially, negating the pattern&#39;s primary advantage: speed through parallelism.</p><h3 id="evaluation-maturity" tabindex="-1">Evaluation maturity <a class="header-anchor" href="#evaluation-maturity" aria-label="Permalink to &quot;Evaluation maturity&quot;">​</a></h3><p>The book describes a 4-stage evaluation maturity curve:</p><table tabindex="0"><thead><tr><th>Stage</th><th>Practices</th><th>Current status</th></tr></thead><tbody><tr><td>Manual</td><td>Run agent, inspect output by hand</td><td><strong>This is where the workflow sits</strong></td></tr><tr><td>Scripted</td><td>Automated test runner, pass/fail checks</td><td>Not implemented</td></tr><tr><td>Automated</td><td>CI/CD integration, LLM-as-judge</td><td>Not applicable</td></tr><tr><td>Production-integrated</td><td>Continuous eval on live traffic</td><td>Not applicable</td></tr></tbody></table><p>The 15-criteria evaluation rubric is strong infrastructure — it just isn&#39;t being used. The gap is procedural, not conceptual.</p><h3 id="skill-description-quality" tabindex="-1">Skill description quality <a class="header-anchor" href="#skill-description-quality" aria-label="Permalink to &quot;Skill description quality&quot;">​</a></h3><p>The book emphasises that model-invoked skill descriptions need three elements for reliable semantic matching:</p><table tabindex="0"><thead><tr><th>Element</th><th>Description</th><th>Current status</th></tr></thead><tbody><tr><td>Trigger terms</td><td>Synonyms and domain terms for semantic matching</td><td>Minimal</td></tr><tr><td>Scope boundaries</td><td>&quot;NOT for&quot; clauses preventing wrong activation</td><td><strong>Not present</strong></td></tr><tr><td>Differentiation</td><td>How this skill differs from similar ones</td><td><strong>Not present</strong></td></tr></tbody></table><p>Example comparison:</p><p><strong>Current architect description:</strong></p><blockquote><p>Design technically coherent AI systems for WordPress and Laravel environments.</p></blockquote><p><strong>Improved description (following the book&#39;s pattern):</strong></p><blockquote><p>Design technically coherent AI systems for WordPress and Laravel environments. Use when evaluating system architecture, tool selection, integration feasibility, data flow, or scalability for AI initiatives. NOT for cost analysis (use cost-governor), governance policy (use governance), or business prioritisation (use strategist).</p></blockquote><h3 id="the-empty-strategist" tabindex="-1">The empty strategist <a class="header-anchor" href="#the-empty-strategist" aria-label="Permalink to &quot;The empty strategist&quot;">​</a></h3><p>The strategist skill is referenced throughout the orchestration chain but contains no content. On the book&#39;s framework, this creates a cascade of problems:</p><ul><li>No description means it will never be semantically matched (model-invoked failure)</li><li>No behavioural constraints means unpredictable output when manually invoked</li><li>No output structure means the reconciliation agent can&#39;t rely on consistent strategist input</li><li>No &quot;You DO NOT&quot; section means the strategist may duplicate work from other agents</li></ul><p>This should be populated before any other improvements, as it&#39;s a foundational gap that affects every run of the workflow.</p>',43)])])}const g=e(n,[["render",i]]);export{m as __pageData,g as default};
